+// ═════════════════════════════════════════════════════════════════════════
+// 1. Non-overlapping rects: horizontal layout
+// ═════════════════════════════════════════════════════════════════════════
+
+proptest! {
+    #[test]
+    fn horizontal_rects_never_overlap(
+        constraints in extended_constraint_list(10),
+        width in 1u16..=500,
+        height in 1u16..=200,
+        gap in 0u16..=20,
+        alignment in alignment_strategy(),
